<?php
namespace App\Models;use App\Core\{Auth,Database};
final class AiAssistant{
 public static function language(string$text):string{return preg_match('/[\x{0980}-\x{09FF}]/u',$text)?'bn':'en';}
 private static function lower(string$text):string{return mb_strtolower(trim($text),'UTF-8');}
 private static function keywordMatch(string$text,?string$csv):int{$score=0;foreach(array_filter(array_map('trim',explode(',',self::lower((string)$csv))))as$keyword)if($keyword!==''&&mb_strpos($text,$keyword)!==false)$score+=max(1,mb_strlen($keyword));return$score;}
 public static function conversation(string$key,?int$userId,string$lang):int{$pdo=Database::connection();$s=$pdo->prepare('SELECT id FROM ai_conversations WHERE conversation_key=?');$s->execute([$key]);$id=$s->fetchColumn();if($id){$pdo->prepare('UPDATE ai_conversations SET user_id=COALESCE(user_id,?),language=?,last_message_at=NOW() WHERE id=?')->execute([$userId,$lang,$id]);return(int)$id;}$s=$pdo->prepare('INSERT INTO ai_conversations(conversation_key,user_id,language)VALUES(?,?,?)');$s->execute([$key,$userId,$lang]);return(int)$pdo->lastInsertId();}
 private static function saveMessage(int$conversation,string$sender,string$message,?string$intent=null,?float$confidence=null,array$meta=[]):void{$s=Database::connection()->prepare('INSERT INTO ai_messages(conversation_id,sender,message,intent,confidence,metadata)VALUES(?,?,?,?,?,?)');$s->execute([$conversation,$sender,$message,$intent,$confidence,$meta?json_encode($meta,JSON_UNESCAPED_UNICODE):null]);}
 public static function respond(string$key,?int$userId,string$message):array{$lang=self::language($message);$text=self::lower($message);$conversation=self::conversation($key,$userId,$lang);self::saveMessage($conversation,'user',$message);$result=self::emergency($text,$lang)??self::symptom($text,$lang)??self::doctorSchedule($text,$lang)??self::faq($text,$lang)??self::fallback($conversation,$message,$lang);self::saveMessage($conversation,'assistant',$result['reply'],$result['intent'],$result['confidence'],$result);return$result+['language'=>$lang,'conversation_key'=>$key];}
 private static function emergency(string$text,string$lang):?array{$rows=Database::connection()->query('SELECT * FROM symptoms WHERE is_active=1 AND is_emergency=1 ORDER BY id')->fetchAll();foreach($rows as$r){$score=max(self::keywordMatch($text,$r['keywords_en']),self::keywordMatch($text,$r['keywords_bn']));if($score>0){$reply=$lang==='bn'?($r['emergency_message_bn']?:$r['emergency_message_en']):$r['emergency_message_en'];return['reply'=>$reply,'intent'=>'emergency','confidence'=>1.0,'emergency'=>true,'actions'=>[['label'=>$lang==='bn'?'জরুরি কল ১০৬৭৮':'Call Emergency 10678','url'=>'tel:10678'],['label'=>$lang==='bn'?'অ্যাম্বুলেন্স':'Ambulance','url'=>'tel:01713106787']],'cards'=>[],'disclaimer'=>$lang==='bn'?'এটি রোগ নির্ণয় নয়। জরুরি অবস্থায় চ্যাট ব্যবহার করবেন না।':'This is not a diagnosis. Do not use chat during an emergency.'];}}return null;}
 private static function symptom(string$text,string$lang):?array{$sql='SELECT s.*,r.recommendation_en,r.recommendation_bn,r.priority,d.id department_id,d.name department_name,d.short_description FROM symptoms s JOIN symptom_department_rules r ON r.symptom_id=s.id AND r.is_active=1 JOIN departments d ON d.id=r.department_id AND d.is_active=1 WHERE s.is_active=1 AND s.is_emergency=0 ORDER BY r.priority DESC';$rows=Database::connection()->query($sql)->fetchAll();$best=null;$bestScore=0;foreach($rows as$r){$score=max(self::keywordMatch($text,$r['keywords_en']),self::keywordMatch($text,$r['keywords_bn']));if($score>$bestScore){$best=$r;$bestScore=$score;}}if(!$best)return null;$s=Database::connection()->prepare('SELECT id,name,designation,qualifications,experience_years FROM doctors d JOIN doctor_departments dd ON dd.doctor_id=d.id WHERE dd.department_id=? AND d.is_active=1 ORDER BY d.is_featured DESC,d.experience_years DESC LIMIT 3');$s->execute([$best['department_id']]);$doctors=$s->fetchAll();$cards=[['kind'=>'department','title'=>$best['department_name'],'subtitle'=>$best['short_description'],'url'=>'department?id='.$best['department_id']]];foreach($doctors as$d)$cards[]=['kind'=>'doctor','title'=>$d['name'],'subtitle'=>$d['designation'].' • '.$d['experience_years'].' years','url'=>'doctor?id='.$d['id'],'book_url'=>'book-appointment?doctor='.$d['id']];$reply=$lang==='bn'?($best['recommendation_bn']?:$best['recommendation_en']):$best['recommendation_en'];return['reply'=>$reply,'intent'=>'department_recommendation','confidence'=>min(.95,.55+$bestScore/100),'emergency'=>false,'cards'=>$cards,'actions'=>[['label'=>$lang==='bn'?'বিভাগ দেখুন':'View Department','url'=>'department?id='.$best['department_id']],['label'=>$lang==='bn'?'ডাক্তার খুঁজুন':'Find Doctors','url'=>'doctors?department='.$best['department_id']]],'disclaimer'=>$lang==='bn'?'এই পরামর্শ শুধু হাসপাতালের বিভাগ খুঁজতে সাহায্য করে; এটি রোগ নির্ণয় নয়।':'This recommendation is for hospital navigation only; it is not a diagnosis.'];}
 private static function doctorSchedule(string$text,string$lang):?array{$wantsSchedule=self::keywordMatch($text,'doctor time,schedule,available,visiting,when')||self::keywordMatch($text,'ডাক্তার সময়,সময়সূচি,কখন,কোন দিন,চেম্বার');if(!$wantsSchedule)return null;$doctors=Database::connection()->query('SELECT id,name,designation,available_days,available_time FROM doctors WHERE is_active=1')->fetchAll();foreach($doctors as$d)if(mb_strpos($text,self::lower($d['name']))!==false||mb_strpos($text,self::lower(str_replace('Dr. ','',$d['name'])))!==false){$reply=$lang==='bn'?$d['name'].' সাধারণত '.$d['available_days'].' দিনে '.$d['available_time'].' সময়ে রোগী দেখেন। বুক করার আগে খালি স্লট নিশ্চিত করুন।':$d['name'].' usually visits on '.$d['available_days'].' from '.$d['available_time'].'. Confirm an available slot before visiting.';return['reply'=>$reply,'intent'=>'doctor_schedule','confidence'=>.9,'emergency'=>false,'cards'=>[['kind'=>'doctor','title'=>$d['name'],'subtitle'=>$d['designation'],'url'=>'doctor?id='.$d['id'],'book_url'=>'book-appointment?doctor='.$d['id']]],'actions'=>[['label'=>$lang==='bn'?'অ্যাপয়েন্টমেন্ট বুক করুন':'Book Appointment','url'=>'book-appointment?doctor='.$d['id']]],'disclaimer'=>''];}return null;}
 private static function faq(string$text,string$lang):?array{$rows=Database::connection()->query('SELECT * FROM ai_knowledge_base WHERE is_active=1 ORDER BY priority DESC')->fetchAll();$best=null;$bestScore=0;foreach($rows as$r){$score=self::keywordMatch($text,$lang==='bn'?$r['keywords_bn']:$r['keywords_en']);if($score>$bestScore){$best=$r;$bestScore=$score;}}if(!$best||$bestScore<3)return null;$reply=$lang==='bn'?($best['answer_bn']?:$best['answer_en']):$best['answer_en'];$actions=[];if($best['category']==='appointment')$actions[]=['label'=>$lang==='bn'?'অ্যাপয়েন্টমেন্ট বুক করুন':'Book Appointment','url'=>Auth::check()?'book-appointment':'login'];if($best['category']==='diagnostics')$actions[]=['label'=>$lang==='bn'?'পরীক্ষা দেখুন':'View Tests','url'=>'diagnostics'];if($best['category']==='cabins')$actions[]=['label'=>$lang==='bn'?'কেবিন দেখুন':'View Cabins','url'=>'cabins'];return['reply'=>$reply,'intent'=>'faq_'.$best['category'],'confidence'=>min(.95,.6+$bestScore/100),'emergency'=>false,'cards'=>[],'actions'=>$actions,'disclaimer'=>''];}
 private static function fallback(int$conversation,string$query,string$lang):array{$pdo=Database::connection();$s=$pdo->prepare('SELECT id FROM ai_unanswered_queries WHERE query_text=? AND language=? AND status IN("new","reviewing") LIMIT 1');$s->execute([$query,$lang]);$id=$s->fetchColumn();if($id)$pdo->prepare('UPDATE ai_unanswered_queries SET occurrence_count=occurrence_count+1,last_seen_at=NOW() WHERE id=?')->execute([$id]);else$pdo->prepare('INSERT INTO ai_unanswered_queries(conversation_id,query_text,language)VALUES(?,?,?)')->execute([$conversation,$query,$lang]);return['reply'=>$lang==='bn'?'দুঃখিত, এই প্রশ্নের নিশ্চিত উত্তর আমার জ্ঞানভাণ্ডারে নেই। প্রশ্নটি হাসপাতাল টিমের পর্যালোচনার জন্য রাখা হয়েছে। আপনি ডাক্তার, বিভাগ, অ্যাপয়েন্টমেন্ট, ডায়াগনস্টিক, কেবিন বা ভিজিটিং সময় সম্পর্কে জিজ্ঞাসা করতে পারেন।':'I do not have a verified answer for that question yet. It has been added for the hospital team to review. You can ask about doctors, departments, appointments, diagnostics, cabins or visiting hours.','intent'=>'unanswered','confidence'=>0.0,'emergency'=>false,'cards'=>[],'actions'=>[['label'=>$lang==='bn'?'হাসপাতালে যোগাযোগ':'Contact Hospital','url'=>'contact']],'disclaimer'=>''];}
 public static function history(string$key):array{$s=Database::connection()->prepare('SELECT m.sender,m.message,m.created_at FROM ai_messages m JOIN ai_conversations c ON c.id=m.conversation_id WHERE c.conversation_key=? ORDER BY m.id DESC LIMIT 30');$s->execute([$key]);return array_reverse($s->fetchAll());}
 public static function knowledge():array{return Database::connection()->query('SELECT * FROM ai_knowledge_base ORDER BY category,priority DESC,id DESC')->fetchAll();}
 public static function knowledgeOne(int$id):?array{$s=Database::connection()->prepare('SELECT * FROM ai_knowledge_base WHERE id=?');$s->execute([$id]);return$s->fetch()?:null;}
 public static function saveKnowledge(array$d):void{$id=(int)($d['id']??0);$values=[$d['category'],$d['question_en'],$d['answer_en'],$d['question_bn']?:null,$d['answer_bn']?:null,$d['keywords_en'],$d['keywords_bn']?:null,(int)$d['priority'],isset($d['is_active']),Auth::id()];if($id){$s=Database::connection()->prepare('UPDATE ai_knowledge_base SET category=?,question_en=?,answer_en=?,question_bn=?,answer_bn=?,keywords_en=?,keywords_bn=?,priority=?,is_active=?,created_by=? WHERE id=?');$s->execute([...$values,$id]);}else{$s=Database::connection()->prepare('INSERT INTO ai_knowledge_base(category,question_en,answer_en,question_bn,answer_bn,keywords_en,keywords_bn,priority,is_active,created_by)VALUES(?,?,?,?,?,?,?,?,?,?)');$s->execute($values);$id=(int)Database::connection()->lastInsertId();}Admin::audit(($d['id']??null)?'update':'create','ai_knowledge_base',$id);}
 public static function symptoms():array{return Database::connection()->query('SELECT s.*,GROUP_CONCAT(d.name SEPARATOR ", ") departments FROM symptoms s LEFT JOIN symptom_department_rules r ON r.symptom_id=s.id LEFT JOIN departments d ON d.id=r.department_id GROUP BY s.id ORDER BY s.is_emergency DESC,s.name_en')->fetchAll();}
 public static function symptomOne(int$id):?array{$s=Database::connection()->prepare('SELECT s.*,r.department_id,r.recommendation_en,r.recommendation_bn,r.priority FROM symptoms s LEFT JOIN symptom_department_rules r ON r.symptom_id=s.id AND r.is_active=1 WHERE s.id=? LIMIT 1');$s->execute([$id]);return$s->fetch()?:null;}
 public static function saveSymptom(array$d):void{if(empty($d['name_en'])||empty($d['keywords_en']))throw new \RuntimeException('English symptom label and keywords are required.');if(isset($d['is_emergency'])&&empty($d['emergency_message_en']))throw new \RuntimeException('Emergency rules require a clear English emergency message.');if(!isset($d['is_emergency'])&&(empty($d['department_id'])||empty($d['recommendation_en'])))throw new \RuntimeException('Navigation rules require a department and recommendation.');$id=(int)($d['id']??0);$vals=[$d['name_en'],$d['name_bn']?:null,$d['keywords_en'],$d['keywords_bn']?:null,isset($d['is_emergency']),$d['emergency_message_en']?:null,$d['emergency_message_bn']?:null,isset($d['is_active'])];$pdo=Database::connection();$pdo->beginTransaction();try{if($id){$s=$pdo->prepare('UPDATE symptoms SET name_en=?,name_bn=?,keywords_en=?,keywords_bn=?,is_emergency=?,emergency_message_en=?,emergency_message_bn=?,is_active=? WHERE id=?');$s->execute([...$vals,$id]);}else{$s=$pdo->prepare('INSERT INTO symptoms(name_en,name_bn,keywords_en,keywords_bn,is_emergency,emergency_message_en,emergency_message_bn,is_active)VALUES(?,?,?,?,?,?,?,?)');$s->execute($vals);$id=(int)$pdo->lastInsertId();}if(!empty($d['department_id'])&&!isset($d['is_emergency'])){$s=$pdo->prepare('INSERT INTO symptom_department_rules(symptom_id,department_id,recommendation_en,recommendation_bn,priority,is_active)VALUES(?,?,?,?,?,1) ON DUPLICATE KEY UPDATE recommendation_en=VALUES(recommendation_en),recommendation_bn=VALUES(recommendation_bn),priority=VALUES(priority),is_active=1');$s->execute([$id,$d['department_id'],$d['recommendation_en'],$d['recommendation_bn']?:null,(int)$d['priority']]);}Admin::audit(($d['id']??null)?'update':'create','symptoms',$id);$pdo->commit();}catch(\Throwable$e){$pdo->rollBack();throw$e;}}
 public static function unanswered():array{return Database::connection()->query('SELECT q.*,c.conversation_key FROM ai_unanswered_queries q LEFT JOIN ai_conversations c ON c.id=q.conversation_id ORDER BY q.status="new" DESC,q.occurrence_count DESC,q.last_seen_at DESC')->fetchAll();}
 public static function resolveUnanswered(int$id,string$status,string$note):void{$allowed=['new','reviewing','resolved','ignored'];if(!in_array($status,$allowed,true))throw new \RuntimeException('Invalid status.');$s=Database::connection()->prepare('UPDATE ai_unanswered_queries SET status=?,resolution_note=?,resolved_by=? WHERE id=?');$s->execute([$status,$note?:null,Auth::id(),$id]);Admin::audit('status_change','ai_unanswered_queries',$id,['status'=>$status]);}
}
